const item = $input.first();
const text = String(item.json.text ?? "").trim();
const fileName = item.binary?.file?.fileName ?? item.json.fileName ?? "unknown";

// Pre-check: văn bản quá ngắn có thể là PDF scan (ảnh)
if (text.length < 80) {
  return [{
    json: {
      _error: "LOW_TEXT_CONTENT",
      _errorMessage: `Văn bản trích xuất quá ngắn (${text.length} ký tự). File có thể là PDF scan (ảnh). Vui lòng dùng file có text layer hoặc chạy OCR trước.`,
      textLength: text.length,
      fileName,
    }
  }];
}

return [{
  json: {
    extractedText: text,
    textLength: text.length,
    fileName,
    _startTime: Date.now(),
  }
}];

const item = $input.first();
const text = String(item.json.extractedText ?? "");
const s = text.toLowerCase();

const score = { NDA: 0, Employment: 0, Lease: 0, Service: 0, Sales: 0, Other: 0 };
const hit = (label, n = 1) => { score[label] = (score[label] ?? 0) + n; };

// NDA
if (s.includes("non-disclosure") || s.includes("non disclosure") || s.includes("confidentiality agreement")) hit("NDA", 4);
if (s.includes("confidential") || s.includes("proprietary information")) hit("NDA", 2);
if (s.includes("nda")) hit("NDA", 3);
if (s.includes("bảo mật") || s.includes("không tiết lộ") || s.includes("thông tin mật") || s.includes("thỏa thuận bảo mật")) hit("NDA", 4);

// Employment
if (s.includes("employment agreement") || s.includes("employment contract")) hit("Employment", 5);
if (s.includes("employee") || s.includes("employer") || s.includes("offer letter")) hit("Employment", 3);
if (s.includes("probation") || s.includes("salary") || s.includes("compensation") || s.includes("annual leave")) hit("Employment", 2);
if (s.includes("hợp đồng lao động") || s.includes("người lao động") || s.includes("người sử dụng lao động")) hit("Employment", 5);
if (s.includes("thử việc") || s.includes("lương") || s.includes("phụ cấp") || s.includes("nghỉ phép")) hit("Employment", 2);

// Lease
if (s.includes("lease agreement") || s.includes("tenancy agreement") || s.includes("rental agreement")) hit("Lease", 5);
if (s.includes("landlord") || s.includes("tenant") || s.includes("premises") || s.includes("deposit")) hit("Lease", 3);
if (s.includes("hợp đồng thuê") || s.includes("bên cho thuê") || s.includes("bên thuê") || s.includes("tiền đặt cọc")) hit("Lease", 5);
if (s.includes("tiền thuê") || s.includes("mặt bằng") || s.includes("căn hộ") || s.includes("văn phòng")) hit("Lease", 2);

// Service
if (s.includes("service agreement") || s.includes("services agreement") || s.includes("statement of work")) hit("Service", 5);
if (s.includes("sow") || s.includes("maintenance") || s.includes("support services") || s.includes("deliverable")) hit("Service", 3);
if (s.includes("hợp đồng dịch vụ") || s.includes("cung cấp dịch vụ")) hit("Service", 5);
if (s.includes("dịch vụ") || s.includes("bảo trì") || s.includes("tư vấn") || s.includes("triển khai") || s.includes("phát triển phần mềm")) hit("Service", 3);

// Sales
if (s.includes("purchase agreement") || s.includes("sale agreement") || s.includes("purchase order")) hit("Sales", 5);
if (s.includes("buyer") || s.includes("seller") || s.includes("goods") || s.includes("delivery") || s.includes("warranty")) hit("Sales", 3);
if (s.includes("hợp đồng mua bán") || s.includes("mua bán hàng hóa")) hit("Sales", 5);
if (s.includes("đơn đặt hàng") || s.includes("bên mua") || s.includes("bên bán") || s.includes("hàng hóa") || s.includes("giao hàng")) hit("Sales", 3);

// Other
if (s.includes("policy") || s.includes("handbook") || s.includes("quy chế") || s.includes("nội quy")) hit("Other", 1);

let best = "Other", bestScore = -1, second = -1;
for (const [k, v] of Object.entries(score)) {
  if (v > bestScore) { second = bestScore; bestScore = v; best = k; }
  else if (v > second) { second = v; }
}

const total = Object.values(score).reduce((a, b) => a + b, 0);
const margin = bestScore - second;
let hintConfidence = 0;
if (best !== "Other" && bestScore >= 3) {
  hintConfidence = Math.max(0.35, Math.min(0.92, (bestScore / Math.max(1, total)) + (margin * 0.08)));
}

const topSignals = Object.entries(score)
  .filter(([, v]) => v > 0)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 3)
  .map(([k, v]) => `${k}:${v}`);

return [{
  json: {
    ...item.json,
    docTypeHint: best,
    docTypeHintConfidence: Number(hintConfidence.toFixed(2)),
    docTypeHintSignals: topSignals,
  }
}];

const item = $input.first();
const raw = item.json.text;
const startTime = item.json._startTime ?? Date.now();
const fileName = item.json.fileName ?? "unknown";
const textLength = item.json.textLength ?? 0;
const docTypeHint = item.json.docTypeHint ?? "Other";
const docTypeHintConfidence = item.json.docTypeHintConfidence ?? 0;
const docTypeHintSignals = item.json.docTypeHintSignals ?? [];

const allowed = new Set(["NDA", "Employment", "Lease", "Service", "Sales", "Other"]);
const validSeverities = new Set(["low", "medium", "high"]);
const validCategories = new Set(["liability", "termination", "payment", "ip", "governing_law", "indemnification", "auto_renewal", "other"]);
const validActions = new Set(["approve", "review", "reject"]);

const fallback = (extra = {}) => ({
  success: false,
  docType: "Other",
  confidence: 0,
  riskScore: 0,
  riskLevel: "Low",
  riskFlags: [],
  keyParties: [],
  contractValue: null,
  effectiveDate: null,
  expiryDate: null,
  governingLaw: null,
  autoRenewal: null,
  recommendedAction: "review",
  reviewNotes: null,
  summary: "",
  meta: {
    fileName,
    textLength,
    processingTimeMs: Date.now() - startTime,
    docTypeHint,
    docTypeHintConfidence,
    docTypeHintSignals,
  },
  ...extra,
});

if (!raw) return [{ json: fallback({ error: "NO_MODEL_OUTPUT", errorMessage: "Không nhận được kết quả từ mô hình AI." }) }];

let s = String(raw).trim()
  .replace(/^```json\s*/i, "")
  .replace(/^```\s*/i, "")
  .replace(/```$/i, "")
  .trim();

let parsed;
try {
  parsed = JSON.parse(s);
} catch {
  return [{ json: fallback({ error: "AI_OUTPUT_PARSE_ERROR", errorMessage: "AI trả về dữ liệu không phải JSON hợp lệ.", rawOutput: s.slice(0, 500) }) }];
}

// Normalize docType
const docRaw = String(parsed.docType ?? "Other").trim();
const docNorm = docRaw.toLowerCase();
let docType = "Other";
if (allowed.has(docRaw)) docType = docRaw;
else if (docNorm.includes("nda") || docNorm.includes("non-disclosure") || docNorm.includes("non disclosure")) docType = "NDA";
else if (docNorm.includes("employment") || docNorm.includes("lao động") || docNorm.includes("labor")) docType = "Employment";
else if (docNorm.includes("lease") || docNorm.includes("rent") || docNorm.includes("thuê")) docType = "Lease";
else if (docNorm.includes("service") || docNorm.includes("dịch vụ") || docNorm.includes("consult")) docType = "Service";
else if (docNorm.includes("sales") || docNorm.includes("purchase") || docNorm.includes("mua bán")) docType = "Sales";

// Normalize numbers
let confidence = Math.max(0, Math.min(1, Number(parsed.confidence ?? 0)));
if (!Number.isFinite(confidence)) confidence = 0;

let riskScore = Math.max(0, Math.min(100, Number(parsed.riskScore ?? 0)));
if (!Number.isFinite(riskScore)) riskScore = 0;

const riskLevel = riskScore >= 67 ? "High" : riskScore >= 34 ? "Medium" : "Low";

// Normalize riskFlags (new structured format)
let riskFlags = [];
if (Array.isArray(parsed.riskFlags)) {
  riskFlags = parsed.riskFlags
    .filter(f => f && typeof f === "object" && typeof f.description === "string" && f.description.trim())
    .map(f => ({
      severity: validSeverities.has(String(f.severity ?? "").toLowerCase()) ? String(f.severity).toLowerCase() : "medium",
      category: validCategories.has(String(f.category ?? "").toLowerCase()) ? String(f.category).toLowerCase() : "other",
      description: String(f.description).trim(),
    }))
    .slice(0, 20);
}

// Normalize other fields
const keyParties = Array.isArray(parsed.keyParties)
  ? parsed.keyParties.filter(p => typeof p === "string" && p.trim()).slice(0, 4)
  : [];

const contractValue = parsed.contractValue ? String(parsed.contractValue).trim() : null;
const effectiveDate = parsed.effectiveDate ? String(parsed.effectiveDate).trim() : null;
const expiryDate = parsed.expiryDate ? String(parsed.expiryDate).trim() : null;
const governingLaw = parsed.governingLaw ? String(parsed.governingLaw).trim() : null;
const autoRenewal = typeof parsed.autoRenewal === "boolean" ? parsed.autoRenewal : null;
const recommendedAction = validActions.has(String(parsed.recommendedAction ?? "").toLowerCase())
  ? String(parsed.recommendedAction).toLowerCase()
  : "review";
const reviewNotes = parsed.reviewNotes ? String(parsed.reviewNotes).trim() : null;
const summary = String(parsed.summary ?? "").trim();

return [{
  json: {
    success: true,
    docType,
    confidence,
    riskScore,
    riskLevel,
    riskFlags,
    keyParties,
    contractValue,
    effectiveDate,
    expiryDate,
    governingLaw,
    autoRenewal,
    recommendedAction,
    reviewNotes,
    summary,
    meta: {
      fileName,
      textLength,
      processingTimeMs: Date.now() - startTime,
      docTypeHint,
      docTypeHintConfidence,
      docTypeHintSignals,
    },
  }
}];
